var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"하아……. 여기까지 들릴 정도로 시끌시끌하구만.","JPN":"はあ……ここまで聞こえるぐらい派手にやり合ってんな。","ENG":"*Sigh* I can hear the fighting all the way from here.","TWN":"哇……聲音大到這邊都聽得到欸？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PMC_SUMMER_NULL_B","text":{"KOREA":"그러게나 말이야. 그래도 오늘만 지나면 당분간 발 뻗고 잘 수 있겠어.","JPN":"だな。でも今日さえ終わればしばらく安心して休める。","ENG":"You don’t say. But we’ll be able to get some rest tomorrow.","TWN":"對啊，但只要過了今天，就可以好好睡一覺囉～"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"그렇지. 대장도 하필이면 이런 찝찝한 의뢰를 받아서는.","JPN":"まあな。隊長もよりによってこんな嫌な依頼を受けてくるなんてな。","ENG":"Yeah. I wish the leader didn’t take this contract, though. I don’t really like it.","TWN":"對啊，誰叫隊長偏偏接受這種不討喜的委託。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"아, 더워 죽겠네. 일 끝나면 대장한테 술이나 한 잔 얻어 먹어야지.","JPN":"あーあ、暑いな。仕事が終わったら隊長から酒でも奢ってもらおう。","ENG":"Darn, it’s hot. I’m gonna ask the leader to buy me a drink when he comes back.","TWN":"熱死了！結束後要叫隊長請喝一杯啦！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PMC_SUMMER_NULL_B","text":{"KOREA":"잠깐, 조용히 해. 저기 사람 아냐?","JPN":"待て、静かに。あそこに何かいるぞ。","ENG":"Wait, be quiet. I think I saw somebody.","TWN":"噓！安靜！你認識她嗎？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"여자잖아? 누구냐!","JPN":"女？　誰だ？","ENG":"A girl? Who are you!","TWN":"那個女生？是誰！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"튜브부터 잠수함까지~♬ 손님을 찾아가는 해변 편의점, 아포칼립스입니다~♪","JPN":"浮き輪から潜水艦まで♬　お客様の所に直接伺うビーチのコンビニ、アポカリプスで～す♪","ENG":"From swim rings to submarines! ♬ We've got everything you need on the beach here at Apocalypse! ♬","TWN":"從游泳圈到潛水艇~♬跟著客人來到海邊的便利店，阿波卡利斯~♪"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"세상에, 이런 날씨에 밖에서 일하고 계시는 거예요?","JPN":"まさかこんな天気の中、外で働いていらっしゃるんですか？","ENG":"Oh my, it's too hot to work outside today!","TWN":"哇賽，天氣這麼熱還在外面工作喔？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"시원한 수박 화채 한 그릇 어떠세요? 지금이라면 무려 50퍼센트나 할인이랍니다?","JPN":"冷たいフルーツポンチはいかがですか？　今ならなんと50％割引中ですよ？","ENG":"How about some nice, cold watermelon? It’s 50% off if you buy now!","TWN":"要不要來杯涼爽的西瓜汁？現在半價喔！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PMC_SUMMER_NULL_B","text":{"KOREA":"뭐야, 아포칼립스는 여기서도 장사를 하네.","JPN":"なんだ、アポカリプスはここでも商売するのか。","ENG":"I didn’t know Apocalypse ran their business here.","TWN":"哇～阿波卡利斯生意做到這邊來喔？！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PMC_SUMMER_NULL_B","text":{"KOREA":"그럼 수박 화채 한 그릇이랑 아무 음료수 두 잔만…….","JPN":"じゃあフルーツポンチ1つと、適当にジュース2杯だけ……","ENG":"Well then, get us a bowl of watermelon and two cups of fruit juice, if you have any...","TWN":"那我要一杯西瓜水果茶，另一杯隨便，兩杯就好…"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"모르면 가만히 있어. 어제 마을에 있었던 여자라고.","JPN":"おいおい、待てよ。昨日村にいた女だぞ。","ENG":"Hey, stop. This is the girl we saw in the village yesterday.","TWN":"你不懂就不要說話，她是昨天在村莊的那個女生啊。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"맞아요. 장사하려고 왔는데 다들 싸우느라 정신이 없으신 거 있죠?","JPN":"はい、そうです。商売をしに来ただけなのに、みんな揉めてばかりで落ち着かないですね。","ENG":"That’s true. But I only came here for business, and you were all too busy fighting each other.","TWN":"對啊，我本來是來做生意的，結果大家都只顧著打來打去。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"그 덕분에 기껏 사들인 코코넛도 팔 곳이 없어졌다니까요.","JPN":"そのせいで、せっかく買い付けたココナッツが売れなくて困っちゃいます。","ENG":"I even brought these nice coconuts, and no one’s buying them.","TWN":"害我好不容易買到的椰子都賣不出去。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PMC_SUMMER_NULL_B","text":{"KOREA":"뭐 어때. 한 잔 하자고.","JPN":"まあ、いいだろう。一杯飲もう。","ENG":"Come on, relax. Let’s have some coconut juice.","TWN":"不管了啦，就喝一杯吧！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PMC_SUMMER_NULL_B","text":{"KOREA":"이제 여기서 얻을 거라곤 그 쓸모없는 음침녀 한 명뿐이잖아.","JPN":"どうせここで手に入るのは気色悪い女しかいないだろ。","ENG":"All we have here is that creepy woman, there’s nothing to worry about.","TWN":"我們就只能在這裡守著那個陰沉女，喝杯果汁很過分嗎？！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PMC_SUMMER_NULL_A","text":{"KOREA":"이봐. 아무리 그래도 그렇지 지금 근무 시간이야.","JPN":"いやあ、でもまだ勤務時間中だぞ。","ENG":"But still, we’re on duty now.","TWN":"喂，不管怎麼樣，現在還是上班時間欸！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_B","face":"UNIT_IDLE"}}}}]`);export{e as default};